import React from 'react';

type StatusType = 
  | 'upcoming' | 'in_transit' | 'delivered' | 'delayed' | 'cancelled'
  | 'available' | 'on_trip' | 'off_duty' | 'suspended'
  | 'active' | 'maintenance' | 'idle' | 'retired'
  | 'scheduled' | 'in_progress' | 'completed'
  | 'draft' | 'sent' | 'paid' | 'overdue';

interface StatusBadgeProps {
  status: StatusType;
}

export function StatusBadge({ status }: StatusBadgeProps) {
  const getStyles = (status: StatusType) => {
    switch (status) {
      // Load Statuses
      case 'upcoming':
        return { bg: 'bg-indigo-50 text-indigo-700 border-indigo-100 dark:bg-indigo-950/30 dark:text-indigo-400 dark:border-indigo-900/50', label: 'Upcoming' };
      case 'in_transit':
        return { bg: 'bg-emerald-50 text-emerald-700 border-emerald-100 dark:bg-emerald-950/30 dark:text-emerald-400 dark:border-emerald-900/50', label: 'In Transit' };
      case 'delivered':
        return { bg: 'bg-slate-100 text-slate-700 border-slate-200 dark:bg-slate-800/50 dark:text-slate-400 dark:border-slate-700/50', label: 'Delivered' };
      case 'delayed':
        return { bg: 'bg-amber-50 text-amber-700 border-amber-100 dark:bg-amber-950/30 dark:text-amber-400 dark:border-amber-900/50', label: 'Delayed' };
      case 'cancelled':
        return { bg: 'bg-rose-50 text-rose-700 border-rose-100 dark:bg-rose-950/30 dark:text-rose-400 dark:border-rose-900/50', label: 'Cancelled' };

      // Driver Statuses
      case 'available':
        return { bg: 'bg-emerald-50 text-emerald-700 border-emerald-100 dark:bg-emerald-950/30 dark:text-emerald-400 dark:border-emerald-900/50', label: 'Available' };
      case 'on_trip':
        return { bg: 'bg-indigo-50 text-indigo-700 border-indigo-100 dark:bg-indigo-950/30 dark:text-indigo-400 dark:border-indigo-900/50', label: 'On Trip' };
      case 'off_duty':
        return { bg: 'bg-slate-100 text-slate-700 border-slate-200 dark:bg-slate-800/50 dark:text-slate-400 dark:border-slate-700/50', label: 'Off Duty' };
      case 'suspended':
        return { bg: 'bg-rose-50 text-rose-700 border-rose-100 dark:bg-rose-950/30 dark:text-rose-400 dark:border-rose-900/50', label: 'Suspended' };

      // Vehicle Statuses
      case 'active':
        return { bg: 'bg-emerald-50 text-emerald-700 border-emerald-100 dark:bg-emerald-950/30 dark:text-emerald-400 dark:border-emerald-900/50', label: 'Active' };
      case 'maintenance':
        return { bg: 'bg-amber-50 text-amber-700 border-amber-100 dark:bg-amber-950/30 dark:text-amber-400 dark:border-amber-900/50', label: 'Maintenance' };
      case 'idle':
        return { bg: 'bg-indigo-50 text-indigo-700 border-indigo-100 dark:bg-indigo-950/30 dark:text-indigo-400 dark:border-indigo-900/50', label: 'Idle' };
      case 'retired':
        return { bg: 'bg-slate-100 text-slate-700 border-slate-200 dark:bg-slate-800/50 dark:text-slate-400 dark:border-slate-700/50', label: 'Retired' };

      // Maintenance Statuses
      case 'scheduled':
        return { bg: 'bg-indigo-50 text-indigo-700 border-indigo-100', label: 'Scheduled' };
      case 'in_progress':
        return { bg: 'bg-amber-50 text-amber-700 border-amber-100', label: 'In Progress' };
      case 'completed':
        return { bg: 'bg-emerald-50 text-emerald-700 border-emerald-100', label: 'Completed' };

      // Invoice Statuses
      case 'draft':
        return { bg: 'bg-slate-100 text-slate-700 border-slate-200', label: 'Draft' };
      case 'sent':
        return { bg: 'bg-indigo-50 text-indigo-700 border-indigo-100', label: 'Sent' };
      case 'paid':
        return { bg: 'bg-emerald-50 text-emerald-700 border-emerald-100', label: 'Paid' };
      case 'overdue':
        return { bg: 'bg-rose-50 text-rose-700 border-rose-100', label: 'Overdue' };

      default:
        return { bg: 'bg-slate-100 text-slate-700 border-slate-200', label: String(status) };
    }
  };

  const { bg, label } = getStyles(status);

  return (
    <span className={`inline-flex items-center px-2.5 py-0.5 rounded-full text-xs font-semibold border ${bg}`}>
      {label}
    </span>
  );
}
